return [{
  json: {
    mailbox_user: String($env.AGENDA_OUTLOOK_USER || 'marre.michael@lfm-fh-swf.de').trim(),
    agenda_folder_id: String($env.AGENDA_OUTLOOK_FOLDER_ID || 'AAMkADM3ZDhmZDc1LTIwYmQtNDlmZS1hMWE2LWI5OTAxYTlkZWIxMAAuAAAAAAAkH0jcZmphQ4D6jBE3b4iQAQA4d7TUfWQcRJjaCy_7yagjAAX0HNZOAAA=').trim(),
    board_id: Number($env.NEXTCLOUD_DECK_BOARD_ID || 1919),
    stack_id_eingang: 5678,
    label_review: 7898,
    poll_top: Math.max(1, Math.min(50, Number($env.AGENDA_POLL_TOP || 20))),
    source_system: 'outlook_agenda_folder'
  }
}];

const cfg = $('Set Config').first().json;
const payload = $input.first().json || {};
const messages = Array.isArray(payload.value) ? payload.value : [];
return messages.map((message) => ({ json: { ...message, __config: cfg } }));

function stripHtml(input) {
  return String(input || '')
    .replace(/<\s*br\s*\/?>/gi, '\n')
    .replace(/<\/?p>/gi, '\n\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}
function chooseCategory(subject) {
  const text = String(subject || '').toLowerCase();
  if (text.includes('beschluss')) return { category: 'Beschluss', labelId: 7913 };
  if (text.includes('diskussion')) return { category: 'Diskussion', labelId: 7910 };
  if (text.includes('info') || text.includes('information')) return { category: 'Information', labelId: 7907 };
  return { category: 'Sonstiges', labelId: 7916 };
}
const mail = $input.first().json || {};
const cfg = mail.__config || {};
const sourceMessageId = String(mail.id || '').trim();
const receivedDate = String(mail.receivedDateTime || '').trim();
const subject = String(mail.subject || '').trim();
const bodyPreview = String(mail.bodyPreview || '').trim();
const bodyText = stripHtml(mail.body?.content || '');
const shortContext = bodyPreview || bodyText || 'Kein Textinhalt verfuegbar';
const title = subject || 'Ohne Betreff';
const categoryResult = chooseCategory(subject);
const submitterEmail = String(mail.from?.emailAddress?.address || '').trim() || 'unbekannt';
const submitterName = String(mail.from?.emailAddress?.name || '').trim() || submitterEmail;
const reviewRequired = !subject || submitterEmail === 'unbekannt' || shortContext === 'Kein Textinhalt verfuegbar';
const importedAt = new Date().toISOString();
const invalidHard = !sourceMessageId || !receivedDate;
const internetMessageId = String(mail.internetMessageId || '').trim();
const description = [
  'Kurzkontext',
  shortContext,
  '',
  `Kategorie: ${categoryResult.category}`,
  'Status: Eingang',
  `Einreicher: ${submitterName}`,
  `E-Mail: ${submitterEmail}`,
  `Eingang: ${receivedDate}`,
  'Gewuenschter Termin: ',
  'Vorbereitung: ',
  'Wiedervorlage/Frist: ',
  `Anhaenge vorhanden: ${mail.hasAttachments ? 'ja' : 'nein'}`,
  `Internet-Message-ID: ${internetMessageId}`,
  '',
  'Technik',
  `source_system: ${cfg.source_system || 'outlook_agenda_folder'}`,
  `source_message_id: ${sourceMessageId}`,
  `source_folder_id: ${cfg.agenda_folder_id || ''}`,
  `imported_at: ${importedAt}`,
  reviewRequired ? 'review_required: true' : 'review_required: false'
].join('\n');
return [{
  json: {
    source_system: cfg.source_system || 'outlook_agenda_folder',
    source_message_id: sourceMessageId,
    source_folder_id: cfg.agenda_folder_id || '',
    internet_message_id: internetMessageId,
    title,
    card_description: description,
    submitter_name: submitterName,
    submitter_email: submitterEmail,
    received_date: receivedDate,
    category: categoryResult.category,
    label_id: categoryResult.labelId,
    stack_id: Number(cfg.stack_id_eingang || 5678),
    board_id: Number(cfg.board_id || 1919),
    review_label_id: Number(cfg.label_review || 7898),
    imported_at: importedAt,
    has_attachments: Boolean(mail.hasAttachments),
    review_required: reviewRequired,
    invalid_hard: invalidHard
  }
}];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
const processed = staticData.agendaProcessedMessageIds || {};
const key = String(item.source_message_id || '').trim();
const alreadyProcessedAt = key ? String(processed[key] || '').trim() : '';
return [{ json: { ...item, duplicate_result: alreadyProcessedAt ? 'duplicate_skip' : 'import_new', duplicate_known_at: alreadyProcessedAt } }];

const created = $input.first().json || {};
const original = $('Validate and Normalize Mail').item.json || {};
return [{ json: { ...original, deck_card_id: created.id, deck_stack_id: original.stack_id } }];

const staticData = $getWorkflowStaticData('global');
const processed = staticData.agendaProcessedMessageIds || {};
const item = $input.first().json || {};
if (item.source_message_id) {
  processed[String(item.source_message_id)] = item.imported_at || new Date().toISOString();
}
staticData.agendaProcessedMessageIds = processed;
return [{ json: item }];
